class Solution:
    def largestValues(self, root):
        levels = {}
        def dfs(node, depth):
            if node is None:
                return
            if depth not in levels or node.val > levels[depth]:
                levels[depth] = max(levels.get(depth, node.val), node.val)
            dfs(node.left, depth + 1)
            dfs(node.right, depth + 1)
        dfs(root, 0)
        return [levels[d] for d in range(len(levels))]

