class Solution:
    def largestValues(self, root):
        if root is None:
            return []
        res = []
        q = [root]
        while q:
            best = q[0].val
            nxt = []
            for node in q:
                if node.val > best:
                    best = node.val
                if node.left:
                    nxt.append(node.left)
                if node.right:
                    nxt.append(node.right)
            res.append(best)
            q = nxt
        return res

