var largestValues = function(root) {
    if (root === null) return [];
    const res = [];
    let q = [root];
    while (q.length) {
        let best = q[0].val;
        const nxt = [];
        for (const node of q) {
            if (node.val > best) best = node.val;
            if (node.left) nxt.push(node.left);
            if (node.right) nxt.push(node.right);
        }
        res.push(best);
        q = nxt;
    }
    return res;
};
